export default function flatten(arr, depth = 1) {
  if (depth === 0) return arr.slice();
  const result = [];
  for (const el of arr) {
    if (Array.isArray(el) && depth > 0) {
      result.push(...flatten(el, depth - 1));
    } else {
      result.push(el);
    }
  }
  return result;
}

