export default function flatten(arr, depth = 1) {
  if (depth === 0) return arr.slice();
  const result = [];
  const stack = [];
  // Seed stack right-to-left so popping processes left-to-right
  for (let i = arr.length - 1; i >= 0; i--) {
    stack.push([arr[i], depth]);
  }
  while (stack.length) {
    const [curr, d] = stack.pop();
    if (Array.isArray(curr) && d > 0) {
      for (let i = curr.length - 1; i >= 0; i--) {
        stack.push([curr[i], d - 1]);
      }
    } else {
      result.push(curr);
    }
  }
  return result;
}
